      populationS: { name: "\u0447\u0438\u0441\u043B\u043E \u0443\u0441\u043F\u0435\u0445\u043E\u0432 \u0432 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 ", detail: "\u041A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0443\u0441\u043F\u0435\u0448\u043D\u044B\u0445 \u0438\u0441\u043F\u044B\u0442\u0430\u043D\u0438\u0439 \u0432 \u0433\u0435\u043D\u0435\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438." },
      numberPop: { name: "\u0440\u0430\u0437\u043C\u0435\u0440 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438", detail: "\u0420\u0430\u0437\u043C\u0435\u0440 \u0433\u0435\u043D\u0435\u0440\u0430\u043B\u044C\u043D\u043E\u0439 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438" },
