      dates: { name: "\u0434\u0430\u0442\u044B", detail: "\u0413\u0440\u0430\u0444\u0438\u043A \u0434\u0430\u0442 \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043F\u043B\u0430\u0442\u0435\u0436\u0430\u043C \u0434\u043B\u044F \u0434\u0435\u043D\u0435\u0436\u043D\u044B\u0445 \u043F\u043E\u0442\u043E\u043A\u043E\u0432. \u0414\u0430\u0442\u044B \u043C\u043E\u0433\u0443\u0442 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0442\u044C\u0441\u044F \u0432 \u043B\u044E\u0431\u043E\u043C \u043F\u043E\u0440\u044F\u0434\u043A\u0435. " }
